return {
  -- Miscellaneous Plugins
  --
  -- Simple plugins that don't need their own config files:
  --   - plenary.nvim: Lua utility library (dependency for many plugins)
  --   - vim-tmux-navigator: Seamless navigation between vim and tmux panes
  --
  -- Generated by cursor-agent

  {
    "nvim-lua/plenary.nvim",
    "christoomey/vim-tmux-navigator",
  },

  -- File Explorer: nvim-tree
  --
  -- Sidebar file explorer with git integration.
  -- Keybinding: <leader>ee to toggle, <S-Tab> for file info popup.
  --
  -- Generated by cursor-agent

  {
    "nvim-tree/nvim-tree.lua",
    dependencies = "nvim-tree/nvim-web-devicons",
    config = function()
      local nvimtree = require("nvim-tree")

      -- recommended settings from nvim-tree documentation
      vim.g.loaded_netrw = 1
      vim.g.loaded_netrwPlugin = 1

      nvimtree.setup({
        view = {
          width = 35,
          relativenumber = true,
        },
        -- change folder arrow icons
        renderer = {
          indent_markers = {
            enable = true,
          },
          icons = {
            glyphs = {
              folder = {
                arrow_closed = "", -- arrow when folder is closed
                arrow_open = "", -- arrow when folder is open
              },
            },
          },
        },
        -- disable window_picker for
        -- explorer to work well with
        -- window splits
        actions = {
          open_file = {
            window_picker = {
              enable = false,
            },
          },
        },
        filters = {
          custom = { ".DS_Store" },
        },
        git = {
          ignore = false,
        },
      })

      -- set keymaps
      local keymap = vim.keymap -- for conciseness

      keymap.set("n", "<leader>ee", "<cmd>NvimTreeToggle<CR>", { desc = "Toggle file explorer" }) -- toggle file explorer
     -- keymap.set("n", "<leader>ef", "<cmd>NvimTreeFindFileToggle<CR>", { desc = "Toggle file explorer on current file" }) -- toggle file explorer on current file
     -- keymap.set("n", "<leader>ec", "<cmd>nvimtreecollapse<cr>", { desc = "collapse file explorer" }) -- collapse file explorer
     keymap.set("n", "<leader>er", "<cmd>nvimtreerefresh<cr>", { desc = "refresh file explorer" }) -- refresh file explorer
    end
  },

